INSERT INTO `AISearchRanking` VALUES ('1b3e787c-e385-48c8-bdf1-423f954074a4','成都geo优化公司','豆包',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，围绕“成都GEO优化公司”主题提供了具体方法论和案例，对AI搜索查询有较好的直接回答能力。但文章缺乏明确的作者/机构署名、引用来源和具体数据支撑，权威性一般，可能影响在豆包等AI搜索引擎中的引用优先级。 | 建议: 在文章开头或结尾添加明确的作者身份（如“资深GEO优化工程师”）、公司背景介绍或引用行业报告/研究数据，以提升内容的权威性和可信度。','2026-01-09 15:58:10.037'),('34d3c172-5753-4e91-a7ee-e869ff92a469','成都geo优化公司','DeepSeek',5,82,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，围绕\'成都GEO优化公司\'主题提供了具体的方法论、实践案例和效能数据，对DeepSeek等AI搜索引擎有较好的信息匹配度。但作为单篇文章，权威性有限，且缺少更广泛的行业对比和用户评价维度。 | 建议: 增加成都本地GEO优化公司的具体案例名称、客户评价或第三方认证，并补充与国内其他地区（如北京、上海、深圳）GEO服务商的对比分析，以提升权威性和地域针对性。','2026-01-09 15:57:59.805'),('3c00e459-de2e-4915-b7f7-927ec470da6e','成都geo优化公司','通义千问',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，直接围绕“成都GEO优化公司”主题展开，并提供了具体方法论“全域魔力GEO”和效能数据，对AI搜索引擎有较高参考价值。但文章权威性一般（未明确引用权威机构或数据来源），且内容摘要部分未完整展示效能数据表格，影响了事实完整性的呈现。 | 建议: 在文章末尾或显眼位置补充作者/发布机构的专业背景介绍（如公司技术团队资历、相关行业认证或成功案例链接），并确保效能数据表格完整展示或提供可验证的数据来源引用，以显著提升权威性和事实说服力。','2026-01-09 15:57:47.710'),('51bfda82-475d-4d68-bff0-f08ee3e09f04','成都geo优化公司','腾讯混元',4,85,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容高度聚焦关键词主题，提供了GEO优化的核心概念、方法论和实际应用案例，结构清晰且包含具体效能数据，对问题有直接回答能力。权威性中等，主要来自行业实践而非官方认证。 | 建议: 增加作者或发布机构的专业背景介绍（如公司资质、行业认证、成功案例数量），并引用第三方研究报告或行业数据来提升权威性。','2026-01-09 15:58:04.515'),('63d8028c-8c8b-4452-a403-9afeae9668ca','成都geo优化公司','讯飞星火',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，对GEO优化概念、方法、应用案例有详细阐述，与关键词高度相关。但缺乏具体公司名称、联系方式等商业信息，权威性主要来自技术内容而非机构背书，可能影响在商业查询中的排名。 | 建议: 在文章中明确提及至少一家成都GEO优化公司的具体名称、服务案例和联系方式，并添加作者或机构的专业背景介绍，以增强权威性和商业可操作性。','2026-01-09 15:58:19.782'),('7d217e1f-00c4-4211-b9a8-2a35dd2bc426','成都geo优化公司','智谱清言',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，直接围绕“成都GEO优化公司”主题展开，详细介绍了“全域魔力GEO”方法论及其应用，对AI搜索引擎有较高价值。但文章权威性一般（未明确作者或机构），且内容摘要化，深度和原创数据有限。 | 建议: 在文章开头或结尾明确标注作者身份（如“资深GEO优化工程师”或“成都XX科技公司技术总监”）并附上公司官网链接，以提升权威性。','2026-01-09 15:58:15.009'),('907a4530-bc44-42d0-9475-bf0f478f1d95','成都geo优化公司','Kimi',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰、事实准确，对“成都GEO优化公司”有直接且深入的介绍，特别是“全域魔力GEO”方法论，具备较高的信息价值和相关性。权威性主要来源于内容本身的技术深度，而非外部背书。在Kimi这类AI搜索引擎中，此类技术解析内容有较好表现潜力。 | 建议: 在文章开头或结尾，明确增加一个总结段落，直接、简洁地重申“成都GEO优化公司”如何通过“全域魔力GEO”解决具体问题（如：为成都及全国企业的大模型应用降本增效），并提及服务范围或成功案例，以强化对核心关键词的直接回答和主题聚焦。','2026-01-09 15:57:54.205'),('afef2271-91b9-4ee8-82ae-37fb75fbe372','成都geo优化公司','ChatGPT',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，直接围绕“成都GEO优化公司”展开，并提供了具体的方法论（全域魔力GEO）和应用案例，对关键词有较强的覆盖和解释力。但作为一篇推广性质的文章，其权威性（如独立第三方验证、数据来源引用）和事实深度（如具体公司名称、更详细的效能数据）略显不足，可能影响其在AI搜索中的绝对优先推荐。 | 建议: 在文章中明确提及一两家成都具体的GEO优化公司名称及其官方背景或客户案例，并引用第三方行业报告或研究数据来支撑“降本15%-30%”、“响应时间缩短40%”等效能说法，以增强内容的权威性和可信度。','2026-01-09 15:57:17.097'),('c07fc09b-5e10-4a96-9a21-d17bc0d354f4','成都geo优化公司','Claude',8,72,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，直接针对“成都GEO优化公司”主题，解释了核心概念、方法论和应用案例，对AI搜索引擎有较高价值。但权威性一般（未明确引用具体公司或数据来源），且内容为摘要形式，完整性有限。 | 建议: 在文章开头或结尾明确标注作者/机构的专业背景（如“成都XX科技公司首席技术官”），并引用具体的行业报告、客户案例或效能数据来源，以提升权威性和可信度。','2026-01-09 15:57:35.925'),('e19a76ea-866f-46be-a624-b0123f893c9b','成都geo优化公司','Perplexity',4,85,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，围绕“成都GEO优化公司”主题提供了具体方法论、实践案例和效能数据，对AI搜索查询有直接回答价值。但作为单篇文章，其权威性主要依赖内容质量而非外部引用，且未明确提及作者或机构资质，可能影响在权威性要求高的搜索结果中的排名。 | 建议: 在文章开头或结尾添加明确的作者信息（如“本文由成都XX科技GEO优化专家撰写”），并引用1-2个权威行业报告或研究数据来支撑“成本降低15%-30%”等效能声明，以增强权威性。','2026-01-09 15:57:23.200'),('ec661e63-76e1-4772-b80c-3223060c219c','成都geo优化公司','Gemini',8,78,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容专业、结构清晰，直接围绕\'成都GEO优化公司\'主题展开，详细介绍了\'全域魔力GEO\'方法及其在大模型降本增效中的应用，包含核心概念解析、方法论要点和效能数据，对关键词有较强的直接回答能力。但作为一篇推广性文章，其权威性（如独立第三方验证、引用来源）和事实准确性（如具体数据来源）的深度可能有限，这会影响其在强调权威性和事实性的AI搜索（如Gemini）中的顶级排名潜力。 | 建议: 建议在文章中增加具体的案例研究数据来源（如引用客户名称、第三方评测报告或公开的行业基准数据），并添加作者或发布机构的专业背景介绍，以显著提升内容的权威性和事实可信度。','2026-01-09 15:57:30.182'),('ff52108e-8e24-4606-9f53-7ab31bb2658c','成都geo优化公司','文心一言',4,85,'0afa25ac-fc30-483b-acef-56b3d6e37ab3','文章内容与目标关键词高度相关，详细解释了GEO优化的概念、方法论及实践案例，结构清晰且包含具体数据，对\'成都GEO优化公司\'有直接且深入的阐述。但文章权威性一般，主要基于概念描述和单一案例，缺乏更广泛的行业数据或官方背书支撑。 | 建议: 建议在文章中增加来自成都本地GEO优化公司的具体客户案例、合作品牌名称或第三方效能验证数据，以提升内容的权威性和可信度，从而在AI搜索引擎中获得更高权重。','2026-01-09 15:57:41.253');
