INSERT INTO `AIStrategy` VALUES ('2ba4eca4-cfd7-4a2c-938b-6fd9d7b475d0','扁平插画配图','一张现代扁平化风格的插画，解释这个概念：{selection}。色彩明快，线条简洁，适合互联网产品的 UI 插图风格。',0.7,NULL,'IMAGE_CONTENT','2025-12-14 16:37:13.406','2025-12-18 13:19:58.758','IMAGE'),('42fd0e9a-ba6d-425c-a49f-057e4ee2cd8d','抽象创意封面','一张富有创意的抽象艺术图片，灵感来源于：{title}。使用大胆的色彩对比和流动的线条，表现摘要中的核心概念：{summary}。风格类似现代数字艺术，视觉冲击力强。',0.8,NULL,'IMAGE_COVER','2025-12-14 16:37:13.017','2025-12-18 13:19:58.758','IMAGE'),('6d97c00d-0194-46d7-a819-ed7594bd9ba8','商务简约封面','一张专业、极简的商务风格图片，表现主题：{title}。画面构图简洁，使用柔和的自然光，背景可以是现代化的办公室一角或抽象的商务元素。色调以白色、灰色和淡蓝为主，传达信任和专业的品牌形象。',0.7,NULL,'IMAGE_COVER','2025-12-14 16:37:12.821','2025-12-18 13:19:58.758','IMAGE'),('cmijvtkjd00003l9x7ncwfah1','GEO标准优化文章','请以\"{topic}\"为主题，创作一篇针对大模型优化的文章。\n\n关键词：{keywords}\n篇幅要求：{length}\n\n**GEO优化要求**：\n\n1. **清晰的结构层次**\n   - 使用 <h1> 作为主标题（仅一个）\n   - 使用 <h2>、<h3> 构建清晰的内容层次\n   - 每个章节独立完整，可单独理解\n\n2. **问答式内容布局**\n   - 在适当位置加入 \"什么是...?\" \"为什么...?\" \"如何...?\" 等问题\n   - 问题后紧跟详细、准确的回答\n   - 使用 <strong> 标记问题\n\n3. **语义化标记**\n   - 使用 <strong> 标记重要术语和实体（人名、地名、组织）\n   - 使用 <em> 强调关键概念\n   - 使用 <ul>、<li> 列出要点\n\n4. **上下文完整性**\n   - 每段都包含足够的背景信息\n   - 避免使用\"如前所述\"等需要上下文的表达\n   - 确保每个段落都能独立理解\n\n5. **数据和引用**\n   - 包含具体的数据、统计或案例\n   - 使用 <blockquote> 标记引用内容\n\n6. **HTML格式输出**\n   - 使用语义化的HTML标签\n   - 不要包含 <html>、<head>、<body> 等外层标签\n   - 保持良好的代码缩进\n\n**输出示例结构**：\n<h1>主标题</h1>\n<p>引言段落，提供背景和主题概述...</p>\n\n<h2>核心概念</h2>\n<p><strong>什么是[主题]？</strong></p>\n<p>[主题] 是指...</p>\n\n<h2>重要特性/要点</h2>\n<ul>\n  <li><strong>特性1</strong>：详细说明...</li>\n  <li><strong>特性2</strong>：详细说明...</li>\n</ul>\n\n<h2>实际案例/数据</h2>\n<p>根据统计，...</p>\n<blockquote>引用的具体数据或案例</blockquote>\n\n<h2>总结</h2>\n<p>综合以上内容...</p>\n<p>GEO是生成式引擎优化</p>',0.7,4000,'article','2025-11-29 05:59:57.242','2026-01-12 12:18:21.558','WRITING'),('cmijvtlzv00013l9x1r4n526b','FAQ优化文章（问答式）','请以\"{topic}\"为主题，创作一篇问答式（FAQ）格式的文章。\n\n关键词：{keywords}\n篇幅要求：{length}\n\n**FAQ优化要求**：\n\n1. **问题设计**\n   - 包含5-8个常见问题\n   - 问题应该是用户真实会问的\n   - 涵盖\"是什么\"、\"为什么\"、\"如何\"、\"有什么\"等不同类型\n\n2. **回答格式**\n   - 每个回答简洁、准确、完整\n   - 先给出核心答案（1-2句）\n   - 再提供详细说明\n   - 必要时使用列表展开要点\n\n3. **结构化标记**\n   - 使用 <h2> 标记问题\n   - 使用 <p> 和 <ul> 组织答案\n   - 使用 <strong> 标记关键信息\n\n4. **独立性**\n   - 每个Q&A对独立完整\n   - 不依赖其他问答的上下文\n   - 可以被单独引用\n\n**输出格式**：\n<h1>{topic} - 常见问题解答</h1>\n\n<p>以下是关于 <strong>{topic}</strong> 的常见问题及详细解答。</p>\n\n<h2>1. 什么是{topic}？</h2>\n<p><strong>简短答案</strong>：{topic} 是...</p>\n<p>详细说明：...</p>\n\n<h2>2. 为什么{topic}很重要？</h2>\n<p><strong>简短答案</strong>：因为...</p>\n<ul>\n  <li>原因1</li>\n  <li>原因2</li>\n  <li>原因3</li>\n</ul>\n\n<h2>3. 如何使用/实施{topic}？</h2>\n<p><strong>简短答案</strong>：通过以下步骤...</p>\n<ol>\n  <li>步骤1</li>\n  <li>步骤2</li>\n  <li>步骤3</li>\n</ol>\n\n<h2>4. {topic}有哪些优势/特点？</h2>\n<p><strong>主要优势包括</strong>：</p>\n<ul>\n  <li><strong>优势1</strong>：说明</li>\n  <li><strong>优势2</strong>：说明</li>\n</ul>',0.6,3000,'article','2025-11-29 05:59:57.242','2025-11-29 05:59:57.242','WRITING'),('cmijvtm0n00023l9xykbm0epb','知识图谱友好文章','请以\"{topic}\"为主题，创作一篇优化实体关系、便于构建知识图谱的文章。\n\n关键词：{keywords}\n篇幅要求：{length}\n\n**知识图谱优化要求**：\n\n1. **明确的实体标注**\n   - 使用 <strong> 标记所有重要实体（人物、地点、组织、产品、技术）\n   - 首次提及实体时提供完整名称\n   - 示例：<strong>深度学习（Deep Learning）</strong>\n\n2. **清晰的关系表达**\n   - 明确说明实体之间的关系（是什么、属于、包含、应用于等）\n   - 使用\"是...的一种\"、\"属于...\"等明确的关系词\n   - 示例：<strong>TensorFlow</strong> 是由 <strong>Google</strong> 开发的机器学习框架\n\n3. **层次分类**\n   - 使用嵌套列表表示层次关系\n   - 清晰标注上下级关系\n\n4. **定义优先**\n   - 对关键概念提供准确的定义\n   - 定义格式：<strong>概念名称</strong>是指...\n\n5. **HTML结构**\n   - 使用 <dl>、<dt>、<dd> 标记定义列表\n   - 使用语义化标签\n\n**输出示例**：\n<h1>{topic}</h1>\n\n<h2>核心定义</h2>\n<p><strong>{topic}</strong> 是指...</p>\n\n<h2>相关实体</h2>\n<dl>\n  <dt><strong>实体1</strong></dt>\n  <dd>实体1的详细说明，与主题的关系...</dd>\n  \n  <dt><strong>实体2</strong></dt>\n  <dd>实体2的详细说明...</dd>\n</dl>\n\n<h2>层次结构</h2>\n<ul>\n  <li><strong>一级分类</strong>\n    <ul>\n      <li>二级项目1</li>\n      <li>二级项目2</li>\n    </ul>\n  </li>\n</ul>',0.6,3500,'article','2025-11-29 05:59:57.242','2025-11-29 05:59:57.242','WRITING'),('cmijvtm1s00033l9xltscqj29','技术文档优化','请以\"{topic}\"为主题，创作一篇技术文档风格的文章。\n\n关键词：{keywords}\n篇幅要求：{length}\n\n**技术文档优化要求**：\n\n1. **清晰的章节划分**\n   - 概述/简介\n   - 核心概念\n   - 使用方法/步骤\n   - 示例/案例\n   - 常见问题\n   - 最佳实践\n\n2. **代码和示例**\n   - 使用 <pre><code> 标记代码块\n   - 为代码添加注释说明\n   - 提供完整、可运行的示例\n\n3. **步骤说明**\n   - 使用 <ol> 标记有序步骤\n   - 每个步骤清晰、可执行\n   - 包含预期结果\n\n4. **注意事项**\n   - 使用 <blockquote> 标记重要提示\n   - 说明常见错误和解决方案\n\n5. **术语精确**\n   - 使用行业标准术语\n   - 首次使用时解释专业术语\n   - 保持术语一致性\n\n**输出格式**：\n<h1>{topic} 技术文档</h1>\n\n<h2>概述</h2>\n<p>{topic} 是...</p>\n\n<h2>核心概念</h2>\n<p><strong>概念1</strong>：定义和说明</p>\n<p><strong>概念2</strong>：定义和说明</p>\n\n<h2>使用方法</h2>\n<p>以下是使用 {topic} 的详细步骤：</p>\n<ol>\n  <li><strong>步骤1</strong>：详细说明\n    <pre><code>// 示例代码\n示例代码内容</code></pre>\n  </li>\n  <li><strong>步骤2</strong>：详细说明</li>\n</ol>\n\n<h2>实际案例</h2>\n<p>示例场景描述：</p>\n<pre><code>完整的示例代码</code></pre>\n\n<h2>常见问题</h2>\n<p><strong>问题1：错误信息</strong></p>\n<p>解决方案：...</p>\n\n<h2>最佳实践</h2>\n<ul>\n  <li>建议1</li>\n  <li>建议2</li>\n</ul>\n\n<blockquote>\n<strong>重要提示</strong>：特别需要注意的事项...\n</blockquote>',0.5,4000,'article','2025-11-29 05:59:57.242','2025-11-29 05:59:57.242','WRITING'),('cmijvtm3i00043l9xu6im3trl','商业内容优化（产品/服务）','请以\"{topic}\"为主题，创作一篇商业内容文章（产品、服务或解决方案介绍）。\n\n关键词：{keywords}\n篇幅要求：{length}\n\n**商业内容优化要求**：\n\n1. **价值主张清晰**\n   - 开篇明确说明产品/服务是什么\n   - 解决什么问题\n   - 核心价值是什么\n\n2. **特性列表**\n   - 使用 <ul> 列出主要特性\n   - 每个特性包含标题和说明\n   - 使用 <strong> 强调关键词\n\n3. **使用场景**\n   - 提供3-5个典型使用场景\n   - 说明如何解决具体问题\n   - 包含预期效果\n\n4. **对比分析**\n   - 与传统方案或竞品的对比\n   - 使用表格或列表展示差异\n   - 客观公正\n\n5. **行动引导**\n   - 明确的下一步建议\n   - 提供联系方式或了解更多的途径\n\n**输出格式**：\n<h1>{topic}</h1>\n\n<h2>产品/服务概述</h2>\n<p><strong>{topic}</strong> 是一款/一项...，专门为...设计，帮助用户...</p>\n\n<h2>核心特性</h2>\n<ul>\n  <li><strong>特性1：标题</strong>\n    <p>详细说明这个特性的作用和优势...</p>\n  </li>\n  <li><strong>特性2：标题</strong>\n    <p>详细说明...</p>\n  </li>\n  <li><strong>特性3：标题</strong>\n    <p>详细说明...</p>\n  </li>\n</ul>\n\n<h2>适用场景</h2>\n<p><strong>场景1：场景名称</strong></p>\n<p>场景描述：...在这种情况下，{topic} 可以...，实现...</p>\n\n<p><strong>场景2：场景名称</strong></p>\n<p>场景描述：...</p>\n\n<h2>优势对比</h2>\n<p>相比传统方案，<strong>{topic}</strong> 具有以下优势：</p>\n<ul>\n  <li><strong>优势1</strong>：传统方案需要...，而{topic}可以...</li>\n  <li><strong>优势2</strong>：...</li>\n</ul>\n\n<h2>客户收益</h2>\n<p>使用 <strong>{topic}</strong> 后，您可以获得：</p>\n<ul>\n  <li>收益1</li>\n  <li>收益2</li>\n  <li>收益3</li>\n</ul>\n\n<h2>开始使用</h2>\n<p>了解更多关于 <strong>{topic}</strong> 的信息，或开始使用...</p>',0.7,3500,'article','2025-11-29 05:59:57.242','2025-11-29 05:59:57.242','WRITING'),('eaaf4bdc-a1ee-4927-9363-6bd79aee2b50','科技感封面','一张充满未来感的科技风格图片，主题是：{title}。背景包含抽象的数据流和发光的几何图形，色调以深蓝和霓虹青为主，展现高科技和创新的氛围。高质量，高清，3D 渲染风格。',0.7,NULL,'IMAGE_COVER','2025-12-14 16:37:12.546','2025-12-18 13:19:58.758','IMAGE'),('f9ce00f0-c543-49a7-8d5d-d44bc1bb2157','写实风格配图','一张写实风格的照片，准确描绘以下场景：{selection}。光影自然，细节丰富，类似国家地理杂志的摄影风格。',0.8,NULL,'IMAGE_CONTENT','2025-12-14 16:37:13.211','2025-12-18 13:54:35.368','IMAGE');
